import re
from langchain_openai import ChatOpenAI

SYSTEM = """
Answer the question by reasoning step by step using the tools provided.
Format each step exactly as:

Thought: <your reasoning>
Action: <tool_name>[<tool_input>]

After receiving an Observation, continue until you can answer:
Final Answer: <answer>

Tools available:
{tool_descriptions}

Never write the Observation yourself — it will be provided.
"""

def build_tool_descriptions(tools: dict) -> str:
    return "\n".join(
        f"- {name}: {fn.__doc__.splitlines()[0].strip()}"
        for name, fn in tools.items()
    )

def react(question: str, tools: dict, max_steps: int = 8) -> str:
    llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)
    system = SYSTEM.format(tool_descriptions=build_tool_descriptions(tools))
    scratchpad = f"Question: {question}\n"

    for _ in range(max_steps):
        # Stop before LLM writes its own Observation
        response = llm.invoke(
            [{"role": "system", "content": system},
             {"role": "user",   "content": scratchpad}],
        )
        chunk = response.content

        # Trim anything the model wrote after Action: (safety)
        if "Observation:" in chunk:
            chunk = chunk[:chunk.index("Observation:")]
        scratchpad += chunk

        # Check for final answer
        m = re.search(r"Final Answer:\s*(.+)", chunk, re.DOTALL)
        if m:
            return m.group(1).strip()

        # Parse and execute action
        m = re.search(r"Action:\s*(\w[\w_-]*)\[(.+?)\]", chunk, re.DOTALL)
        if m:
            tool_name, tool_input = m.group(1).strip(), m.group(2).strip()
            if tool_name in tools:
                try:
                    obs = str(tools[tool_name](tool_input))[:1200]
                except Exception as e:
                    obs = f"Error: {e}"
            else:
                obs = f"Unknown tool: {tool_name}. Use one of: {list(tools)}"
            scratchpad += f"\nObservation: {obs}\n"
        else:
            scratchpad += "\nObservation: Could not parse action. Use format: Action: tool[input]\n"

    return "Could not answer within the step limit."

import re

ACTION_PATTERN = re.compile(r"Action:\s*(\w[\w_-]*)\[(.+?)\]", re.DOTALL)

def safe_dispatch(llm_output: str, tools: dict) -> str:
    """Parse the action from LLM output and dispatch it, returning an Observation string."""
    m = ACTION_PATTERN.search(llm_output)
    if not m:
        return (
            "Error: could not find a valid Action in your output. "
            f"Available tools: {list(tools.keys())}. "
            "Use the exact format: Action: tool_name[tool_input]"
        )

    tool_name = m.group(1).strip()
    tool_input = m.group(2).strip()

    if tool_name not in tools:
        return (
            f"Error: '{tool_name}' is not a recognised tool. "
            f"Available: {list(tools.keys())}"
        )

    try:
        result = tools[tool_name](tool_input)
        return str(result)[:1200]
    except ValueError as e:
        return f"Error: invalid input for {tool_name} — {e}. Check the expected format."
    except Exception as e:
        return f"Error: {tool_name} failed with {type(e).__name__}: {str(e)[:200]}"

import asyncio
from langchain_core.messages import HumanMessage, AIMessage, ToolMessage

async def stream_react_steps(question: str):
    """Async generator that yields (step_type, content) tuples for each agent step."""
    async for step in app.astream(
        {"messages": [HumanMessage(content=question)]},
        stream_mode="updates",
    ):
        for node_name, updates in step.items():
            for msg in updates.get("messages", []):
                if isinstance(msg, AIMessage):
                    if msg.tool_calls:
                        for tc in msg.tool_calls:
                            yield ("action", f"{tc['name']}({tc['args']})")
                    elif msg.content:
                        yield ("final_answer", msg.content)
                elif isinstance(msg, ToolMessage):
                    yield ("observation", msg.content[:300])

# FastAPI SSE endpoint example
from fastapi import FastAPI
from fastapi.responses import StreamingResponse

app_api = FastAPI()

@app_api.get("/agent")
async def agent_endpoint(question: str):
    async def event_stream():
        async for step_type, content in stream_react_steps(question):
            yield f"data: {step_type}: {content}\n\n"
    return StreamingResponse(event_stream(), media_type="text/event-stream")
